import requests

BASE_URL = "http://127.0.0.1:7860"
FLOW_ID = "your-flow-uuid"

response = requests.post(
    f"{BASE_URL}/api/v1/run/{FLOW_ID}",
    json={
        "input_value": "What is the capital of Japan?",
        "input_type": "chat",
        "output_type": "chat",
        "tweaks": {
            "OpenAI-abc123": {
                "temperature": 0.2,
            }
        },
    },
)
outputs = response.json()["outputs"]
message = outputs[0]["outputs"][0]["results"]["message"]["text"]
print(message)

# Tweaks let you override any component parameter at call time
# without modifying the saved flow

response = requests.post(
    f"http://127.0.0.1:7860/api/v1/run/{FLOW_ID}",
    json={
        "input_value": "Summarise the attached document.",
        "input_type": "chat",
        "output_type": "chat",
        "tweaks": {
            # Use component display name or node ID from the UI
            "OpenAI-abc123": {
                "model_name": "gpt-4o",        # override model
                "temperature": 0.0,
            },
            "Prompt-xyz789": {
                "system_message": "You are a legal document analyst.",
            },
        },
    },
)
